        [Fact]
        public void WFiltro_Computador_Logica_BETWEEN_Verifica_Condicoes_Exatas()
        {
            // Arrange
            var filtro = new FilterOperador
            {
                Computador = 1500,
                Computador_end = 4500,
                LogicalOperator = " AND "
            };
            // Act
            var resultado = _serviceS.WFiltro(filtro);
            // Assert
            resultado.Should().NotBeNull();
